    //     scale$1.domain = function (_) {
    //         return arguments.length ? (scale_domain(hash ? _.map(d => hash(d)) : _), scale$1) : domain;
    //     }
    //     scale$1.range = function (_) {
    //         return arguments.length ? (scale_range(hash ? _.map(d => hash(d)) : _), scale$1) : domain;
    //     }

    //     return scale;
    // },
    d3_scaleTime = d3.scaleTime,
    d3_scalePoint = d3.scalePoint,
    d3_scaleOrdinalOrg = d3.scaleOrdinal, //change
    d3_scaleSqrt = d3.scaleSqrt,
    d3_scaleSymlog = d3.scaleSymlog,
    // bisector

    d3_bisector = d3.bisector,
    // sum

    d3_sum = d3.sum,
    // d3 colors

    d3_hsl = d3.hsl,
    d3_rgb = function() {
        var rgb = d3.rgb.apply(this, arguments);

        /**
         *
         * if the color is transparent, d3.rgb returns NaN, which throws error
         * in some browsers. eg: IE9
         *
         * So, if the color is NaN, we apply black color with 0 opacity.
         */
        if (isNaN(rgb.r) || isNaN(rgb.g) || isNaN(rgb.b)) {
            rgb = d3.rgb(0, 0, 0, rgb.opacity);
        }
        return rgb;
    },
    // d3 merge , map and ser

    d3_merge = d3.merge,
    d3_map = d3.map,
    d3_set = d3.set,
