    topojson = d3.topojson,
    versor = d3.versor,
    d3_geoPath = d3.geoPath,
    d3_geoGraticule = d3.geoGraticule,
    d3_geoCentroid = d3.geoCentroid,
    d3_polygonContains = d3.polygonContains,
    d3_geoDistance = d3.geoDistance,
    d3_geoContains = d3.geoContains,
    d3_quadtree = d3.quadtree,
    //Namespace
    d3_namespace = d3.namespace,
    d3_namespaces = d3.namespaces,
